INSERT INTO tools (name, name_en, category, description, description_en, price, rating, official_url, features, is_recommended, is_hot, is_new, slug, short_tag, full_desc, highlights, drawbacks, tg_advice, tags, sort_order, status) VALUES
('Perplexity Pro', 'Perplexity Pro', '学生', 'AI搜索引擎专业版，支持实时网络搜索、学术文献检索和深度研究报告生成，学术研究必备。', 'Perplexity Pro AI search with real-time web search, academic literature and deep research reports.', '$20/月', 4.7, 'https://www.perplexity.ai', ARRAY['实时网络搜索','学术文献检索','深度研究报告','引用来源追踪'], true, true, true, 'perplexity-pro', 'AI学术搜索', 'Perplexity Pro，实时搜索和学术文献检索AI工具', ARRAY['实时信息准确','来源可追溯','研究报告深入'], ARRAY['价格偏高','深度分析有限'], '学生和研究人员学术搜索首选', ARRAY['热门','2026新品'], 5000, 'active'),
('Elicit AI', 'Elicit', '学生', 'AI学术研究助手，支持自动检索相关论文、提取研究结论和生成文献综述，科研效率提升10倍。', 'AI research assistant auto-finding papers, extracting conclusions and generating literature reviews.', '免费+$12/月', 4.6, 'https://elicit.com', ARRAY['自动论文检索','研究结论提取','文献综述生成','研究问题分析'], true, true, false, 'elicit-ai', 'AI文献综述', 'Elicit AI，自动检索论文和生成文献综述的工具', ARRAY['文献检索全面','结论提取准确','综述生成快'], ARRAY['主要面向英文文献','高级功能需付费'], '研究生和科研人员文献综述首选', ARRAY['热门'], 4950, 'active'),
('Consensus AI', 'Consensus', '学生', 'AI学术搜索引擎，专注于从科学论文中提取共识性结论，帮助研究者快速了解领域共识。', 'AI academic search engine extracting consensus conclusions from scientific papers.', '免费+$9/月', 4.5, 'https://consensus.app', ARRAY['科学共识提取','论文结论对比','研究领域概览','引用质量评估'], false, true, false, 'consensus-ai', 'AI科学共识', 'Consensus AI，从科学论文提取共识结论的搜索引擎', ARRAY['共识提取独特','结论对比直观','质量评估实用'], ARRAY['主要面向英文文献','深度分析有限'], '需要了解研究领域共识的学者', ARRAY['热门'], 4900, 'active'),
('Semantic Scholar AI', 'Semantic Scholar', '学生', 'AI学术搜索引擎，由Allen AI研究院开发，支持语义搜索、论文推荐和引用分析。', 'AI academic search engine by Allen AI with semantic search, paper recommendations and citation analysis.', '免费', 4.5, 'https://www.semanticscholar.org', ARRAY['语义学术搜索','论文智能推荐','引用关系分析','研究趋势追踪'], false, true, false, 'semantic-scholar-ai', 'AI学术搜索', 'Semantic Scholar AI，Allen AI的免费学术语义搜索', ARRAY['完全免费','语义搜索准确','引用分析深入'], ARRAY['界面较简单','中文文献有限'], '学生和研究人员免费学术搜索', ARRAY['热门'], 4850, 'active'),
('Connected Papers', 'Connected Papers', '学生', 'AI论文关系可视化工具，将论文引用关系可视化为图谱，帮助研究者发现相关研究。', 'AI paper relationship visualization tool mapping citation networks to help discover related research.', '免费+$3/月', 4.4, 'https://www.connectedpapers.com', ARRAY['论文引用关系图谱','相关研究发现','研究脉络梳理','领域全景展示'], false, false, false, 'connected-papers', 'AI论文图谱', 'Connected Papers，论文引用关系可视化图谱工具', ARRAY['可视化直观','相关研究发现好','免费版可用'], ARRAY['功能较单一','高级功能需付费'], '研究生梳理研究领域脉络', ARRAY['热门'], 4800, 'active'),
