('Explain Everything AI', 'Explain Everything', '学生', 'AI互动白板工具，支持AI辅助教学内容创作、视频讲解生成和协作学习。', 'AI interactive whiteboard for AI-assisted educational content creation and collaborative learning.', '$8/月起', 4.3, 'https://explaineverything.com', ARRAY['AI辅助教学内容','视频讲解生成','协作白板学习','多媒体整合'], false, false, false, 'explain-everything-ai', 'AI互动白板', 'Explain Everything AI，AI辅助教学内容创作白板', ARRAY['教学内容创作好','协作功能强','多媒体整合好'], ARRAY['价格偏高','学习曲线较陡'], '教师和学生互动教学内容创作', ARRAY['热门'], 3950, 'active'),
