('Socratic AI', 'Socratic', '学生', 'Google旗下AI学习助手，拍照识别题目并提供详细解释和相关学习资源，完全免费。', 'Google AI learning assistant identifying problems from photos with explanations and learning resources.', '免费', 4.4, 'https://socratic.org', ARRAY['拍照识别题目','详细解题解释','相关学习资源','多学科支持'], false, true, false, 'socratic-ai', 'AI学习助手', 'Socratic AI，Google免费拍照识题学习助手', ARRAY['完全免费','Google品质','多学科覆盖'], ARRAY['深度解析有限','主要面向K-12'], '中学生学习辅助和题目解答', ARRAY['热门'], 3850, 'active');
